export function getCityContent(cityObj: { name: string, slug: string, region?: string }) {
  const { name, slug, region } = cityObj;
  
  const specificContent = citySpecificContent[slug];
  
  if (specificContent) {
    return {
      metaTitle: specificContent.metaTitle,
      metaDescription: specificContent.metaDescription,
      heroTitle: specificContent.heroTitle,
      heroSubtitle: specificContent.heroSubtitle,
      region: region || "",
      seoArticleBlocks: specificContent.seoArticleBlocks,
      technicalSpecs: getDefaultTechnicalSpecs(),
      districts: getDefaultDistricts(name, region || ""),
      seoKeywords: generateKeywords(name, region || "")
    };
  }

  const hash = name.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
  const template = fallbackTemplates[hash % fallbackTemplates.length];

  return {
    metaTitle: `Folia Inteligentna ${name} | Montaż Smart Glass i Folia PDLC w ${region}`,
    metaDescription: `Szukasz nowoczesnej folii inteligentnej w mieście ${name}? Profesjonalny montaż Smart Glass i folii PDLC dla biur, domów i gabinetów w ${region}. Sprawdź nasze realizacje!`,
    heroTitle: template.getTitle(name, region || ""),
    heroSubtitle: template.getSubtitle(name),
    region: region || "",
    seoArticleBlocks: template.getBlocks(name, region || ""),
    technicalSpecs: getDefaultTechnicalSpecs(),
    districts: getDefaultDistricts(name, region || ""),
    seoKeywords: generateKeywords(name, region || "")
  };
}

function getDefaultTechnicalSpecs() {
  return [
    { label: "Poziomy prywatności", value: "Przezroczysta, Matowa (80%), Matowa (100%)" },
    { label: "Metody sterowania", value: "Pilot, Aplikacja, Przycisk, BMS" },
    { label: "Pobór mocy", value: "5W/m²" },
    { label: "Gwarancja", value: "2 lata" },
    { label: "Żywotność", value: "100 000 cykli" }
  ];
}

function getDefaultDistricts(cityName: string, region: string): string[] {
  return [
    `Centrum ${cityName}`,
    `Osiedla mieszkaniowe ${cityName}`,
    `Strefa biznesowa ${cityName}`,
    `Dzielnice przemysłowe ${cityName}`
  ];
}

function generateKeywords(city: string, region: string): string[] {
  return [
    `folia inteligentna ${city}`,
    `smart glass ${city}`,
    `folia PDLC ${city}`,
    `montaż folii ${city}`,
    `ścianka szklana ${city}`,
    `folia na okna ${city}`,
    `smart film ${city}`,
    `prywatność na żądanie ${city}`,
    `folia elektryczna ${city}`,
    `szkło przełączalne ${city}`,
    `folia inteligentna ${region}`,
    `smart glass ${region}`,
    `folia PDLC ${region}`
  ];
}

export function getAllCitySlugs(): string[] {
  return seoCities.map(city => city.slug);
}

export function getCityBySlug(slug: string) {
  return seoCities.find(city => city.slug === slug);
}

export function getCitiesByRegion() {
  const regions: Record<string, typeof seoCities> = {};
  seoCities.forEach(city => {
    if (!regions[city.region]) {
      regions[city.region] = [];
    }
    regions[city.region].push(city);
  });
  return regions;
}